import React, { useEffect, useRef } from "react";
import { instance } from "@viz-js/viz";

function escapeLabel(value) {
  return String(value).replace(/\\/g, "\\\\").replace(/"/g, '\\"');
}

function stateSortKey(state) {
  const match = String(state).match(/^q(\d+)$/i);
  if (match) {
    return Number(match[1]);
  }

  const digitMatch = String(state).match(/(\d+)$/);
  return digitMatch ? Number(digitMatch[1]) : Number.MAX_SAFE_INTEGER;
}

const GraphvizViewer = ({ transitions, start, finalStates, title, compact = false }) => {
  const containerRef = useRef(null);

  useEffect(() => {
    if (!containerRef.current) {
      return;
    }

    if (!transitions || transitions.length === 0) {
      containerRef.current.innerHTML = "";
      return;
    }

    const render = async () => {
      const viz = await instance();

      const grouped = new Map();
      transitions
        .filter((t) => Array.isArray(t) && t.length === 3)
        .forEach(([from, symbol, to]) => {
          const key = `${from}__${to}`;
          const existing = grouped.get(key) || { from, to, symbols: new Set() };
          existing.symbols.add(symbol);
          grouped.set(key, existing);
        });

      let dot = "digraph Automata {\n";
      dot += "  rankdir=LR;\n";
      dot += compact
        ? "  graph [bgcolor=\"transparent\", pad=\"0.15\", nodesep=\"0.35\", ranksep=\"0.5\", splines=polyline, overlap=false];\n"
        : "  graph [bgcolor=\"transparent\", pad=\"0.2\", nodesep=\"0.75\", ranksep=\"0.95\", splines=polyline, overlap=false];\n";
      dot += compact
        ? "  node [shape=circle, fontname=\"Poppins\", fontsize=11, color=\"#e8efff\", penwidth=1.4, fontcolor=\"#e8efff\"];\n"
        : "  node [shape=circle, fontname=\"Poppins\", fontsize=13, color=\"#e8efff\", penwidth=1.8, fontcolor=\"#e8efff\"];\n";
      dot += compact
        ? "  edge [fontname=\"JetBrains Mono\", fontsize=10, color=\"#e8efff\", fontcolor=\"#e8efff\"];\n"
        : "  edge [fontname=\"JetBrains Mono\", fontsize=12, color=\"#e8efff\", fontcolor=\"#e8efff\"];\n";

      (finalStates || []).forEach((state) => {
        dot += `  ${escapeLabel(state)} [shape=doublecircle, color="#2dd4bf", penwidth=2.4];\n`;
      });

      if (start) {
        dot += "  start [shape=point, color=\"#2dd4bf\"];\n";
        dot += `  start -> ${escapeLabel(start)} [color="#2dd4bf", penwidth=2];\n`;
      }

      grouped.forEach(({ from, to, symbols }) => {
        const label = Array.from(symbols).sort().map(escapeLabel).join(", ");
        if (from === to) {
          dot += `  ${escapeLabel(from)} -> ${escapeLabel(to)} [label="${label}", constraint=false, minlen=2, labelfloat=true, labeldistance=1.6, arrowsize=0.8];\n`;
        } else {
          dot += `  ${escapeLabel(from)} -> ${escapeLabel(to)} [label="${label}", arrowsize=0.8];\n`;
        }
      });

      dot += "}\n";

      try {
        const svg = viz.renderSVGElement(dot);
        containerRef.current.innerHTML = "";
        containerRef.current.appendChild(svg);
      } catch (error) {
        containerRef.current.innerHTML = "<p>Graph rendering failed.</p>";
      }
    };

    render();
  }, [transitions, start, finalStates]);

  return (
    <section className="graph-card">
      <div className="graph-header-row">
        <h3>{title || "Automata Graph"}</h3>
      </div>
      <div className="graph-canvas" ref={containerRef} />
    </section>
  );
};

export default GraphvizViewer;
